class Solution:
    def generateKey(self, num1, num2, num3):
        s1, s2, s3 = str(num1).zfill(4), str(num2).zfill(4), str(num3).zfill(4)
        key = ''.join(str(min(int(a), int(b), int(c))) for a, b, c in zip(s1, s2, s3))
        return int(key)

